const formResponse = $input.first().json.body.form_response;
const hidden = formResponse.hidden || {};

// Hidden fields passed from the payment redirect
const customerEmail = hidden.email || '';
const firstName = hidden.first_name || '';
const lastName = hidden.last_name || '';
const userId = hidden.user_id || '';

// Build map keyed by Typeform field ID (stable, not order-dependent).
// For multi-select, store the labels array — DO NOT join here.
const answerMap = {};
for (const answer of (formResponse.answers || [])) {
  const fieldId = answer.field.id;
  let value;
  switch (answer.type) {
    case 'text': value = answer.text || ''; break;
    case 'choice': value = answer.choice ? answer.choice.label : ''; break;
    case 'choices': value = answer.choices ? answer.choices.labels : []; break;
    case 'number': value = answer.number || 0; break;
    default: value = answer[answer.type] || '';
  }
  answerMap[fieldId] = value;
}

// === Lookup by Typeform field ID (stable) ===
const FIELD_IDS = {
  process_name:        'CT6McQMxZF6U',
  frustration_type:    'q3dxHdXuzarC',
  monthly_volume:      'KajIvIVqMiYm',
  time_per_instance:   'aX4hUPs0FCMU',
  hourly_rate:         'R9VX682pSZej',
  error_rate:          '4kEhvoROnY3o',
  tools_involved:      'kbAIcPdHztPo',
  decision_complexity: '6d6XTIFLGUIY',
  ideal_state:         'L91EafOtXG38',
  freed_time_impact:   '5lhZXO1EBKnS',
  urgency:             'GGJqfpf5b8HM',
  decision_maker:      'qibFXQ2IoDxE'
};

// Pull raw values
const process_name           = answerMap[FIELD_IDS.process_name] || '';
const frustration_type       = answerMap[FIELD_IDS.frustration_type] || '';
const monthly_volume_raw     = String(answerMap[FIELD_IDS.monthly_volume] || '0');
const time_per_instance_raw  = answerMap[FIELD_IDS.time_per_instance] || '';
const hourly_rate_raw        = answerMap[FIELD_IDS.hourly_rate] || '';
const error_rate_raw         = answerMap[FIELD_IDS.error_rate] || '';
const decision_complexity_raw= answerMap[FIELD_IDS.decision_complexity] || '';
const ideal_state            = answerMap[FIELD_IDS.ideal_state] || '';
const freed_time_impact      = answerMap[FIELD_IDS.freed_time_impact] || '';
const urgency_raw            = answerMap[FIELD_IDS.urgency] || '';
const decision_maker_raw     = answerMap[FIELD_IDS.decision_maker] || '';

// === Tools — keep both array and string versions ===
// Array version: for Airtable multi-select fields (avoids comma-split issues)
// String version: for AI prompts and report prose
const tools_involved_array = Array.isArray(answerMap[FIELD_IDS.tools_involved])
  ? answerMap[FIELD_IDS.tools_involved]
  : (answerMap[FIELD_IDS.tools_involved] ? [answerMap[FIELD_IDS.tools_involved]] : []);
const tools_involved = tools_involved_array.join(', ');

// === Normalisation tables ===
const timeNorm = {
  '5–15 minutes': '5-15min', '5-15 minutes': '5-15min',
  '15–30 minutes': '15-30min', '15-30 minutes': '15-30min',
  '30–60 minutes': '30-60min', '30-60 minutes': '30-60min',
  '1–2 hours': '1-2hrs', '1-2 hours': '1-2hrs',
  '2+ hours': '2+hrs', 'More than 2 hours': '2+hrs'
};
const time_per_instance = timeNorm[time_per_instance_raw] || time_per_instance_raw || '15-30min';

const rateNorm = {
  '$50-75/hr': '$50-75/hr', '$75-100/hr': '$75-100/hr',
  '$100-150/hr': '$100-150/hr', '$150+/hr': '$150+/hr',
  'Not sure': '$75-100/hr'
};
const hourly_rate = rateNorm[hourly_rate_raw] || hourly_rate_raw || '$75-100/hr';

const errorNorm = {
  'Rarely (under 2%)': 'Rarely (<2%)', 'Rarely (<2%)': 'Rarely (<2%)',
  'Occasionally (approx. 5%)': 'Occasionally (~5%)',
  'Occasionally (~5%)': 'Occasionally (~5%)',
  'Often (10%+)': 'Often (10%+)', 'Often (10% or more)': 'Often (10%+)'
};
const error_rate = errorNorm[error_rate_raw] || error_rate_raw || 'Occasionally (~5%)';

const compNorm = {
  'Simple rules, no judgment needed': 'Simple rules / no judgment',
  'Simple rules / no judgment': 'Simple rules / no judgment',
  'Mostly rules with occasional judgment': 'Simple rules with occasional judgment calls',
  'Simple rules with occasional judgment calls': 'Simple rules with occasional judgment calls',
  'Requires context or experience': 'Requires context or experience',
  'Highly subjective or relationship-dependent': 'Highly subjective / relationship-dependent'
};
// Typeform sends the FULL choice label which includes the example in quotes.
// Match by the leading prefix before the colon.
const compPrefix = decision_complexity_raw.split(':')[0].trim();
const compNormPrefix = {
  'Simple Rules': 'Simple rules / no judgment',
  'Judgment Calls': 'Simple rules with occasional judgment calls',
  'Complex Decisions': 'Highly subjective / relationship-dependent'
};
const decision_complexity = compNormPrefix[compPrefix]
  || compNorm[decision_complexity_raw]
  || decision_complexity_raw
  || 'Simple rules with occasional judgment calls';

// === Urgency normalisation (for sales qualification) ===
const urgencyNorm = {
  "It's painful, but we can cope for now.": 'low',
  "It's actively blocking our growth or costing us money.": 'medium',
  "This is a top-3 priority for this quarter.": 'high'
};
const urgency = urgencyNorm[urgency_raw] || 'medium';

// === Decision-maker authority (for whale detection) ===
const decisionMakerNorm = {
  'I can approve this myself.': 'self',
  'I need to get leadership buy-in.': 'leadership',
  'We would need board or executive level approval.': 'board'
};
const decision_maker = decisionMakerNorm[decision_maker_raw] || 'leadership';

// === Whale detection: high authority + medium-or-high urgency ===
const has_authority = (decision_maker === 'self' || decision_maker === 'leadership');
const is_urgent = (urgency === 'high' || urgency === 'medium');
const lead_quality = (has_authority && is_urgent) ? 'whale' : 'standard';

// === Monthly volume parsing ===
// Handles ranges like "80-100" by averaging, or single numbers
const numbers = monthly_volume_raw.match(/\d+/g);
let monthly_volume = 0;
if (numbers && numbers.length >= 2) {
  monthly_volume = Math.round((parseInt(numbers[0]) + parseInt(numbers[1])) / 2);
} else if (numbers && numbers.length === 1) {
  monthly_volume = parseInt(numbers[0]);
}

// === Australian-style date (17 April 2026) ===
const now = new Date();
const ms = ['January','February','March','April','May','June',
            'July','August','September','October','November','December'];
const report_date = `${now.getDate()} ${ms[now.getMonth()]} ${now.getFullYear()}`;

return [{
  json: {
    // === Identity ===
    customer_email: customerEmail,
    first_name: firstName,
    last_name: lastName,
    user_id: userId,

    // === Process intake ===
    process_name,
    frustration_type,
    monthly_volume,
    monthly_volume_raw,
    time_per_instance,
    hourly_rate,
    error_rate,
    tools_involved,         // string for AI prompts/report
    tools_involved_array,   // array for Airtable multi-select
    decision_complexity,
    ideal_state,
    freed_time_impact,

    // === Sales qualification ===
    urgency,
    urgency_raw,
    decision_maker,
    decision_maker_raw,
    lead_quality,

    // === Metadata ===
    report_date
  }
}];

const d = $('Bundle: Audit Data').first().json;
const documentId = $('Copy Template').first().json.id;

const r = (key, fallback = '') => {
  const val = d[key];
  return val !== undefined && val !== null ? String(val) : fallback;
};

// Build placeholder keys using charCode to avoid n8n expression parsing
const b = (name) => String.fromCharCode(123, 123) + name + String.fromCharCode(125, 125);

const fieldMap = {
  'client_name': 'client_name',
  'process_name': 'process_name',
  'report_date': 'report_date',
  'monthly_hours': 'monthly_hours_display',
  'monthly_cost': 'monthly_cost_display',
  'annual_cost': 'annual_cost_display',
  'error_rate': 'error_rate',
  'rework_cost': 'rework_cost_display',
  'frustration_type': 'frustration_type',
  'tools_involved': 'tools_involved',
  'decision_complexity': 'decision_complexity',
  'freed_time_impact': 'freed_time_impact',
  'automation_percentage': 'automation_percentage',
  'automatable_steps': 'automatable_steps',
  'human_required_steps': 'human_required_steps',
  'remaining_human_work': 'remaining_human_work',
  'solution_approach': 'solution_approach',
  'key_integrations': 'key_integrations',
  'trigger_event': 'trigger_event',
  'exception_handling': 'exception_handling',
  'time_savings_monthly': 'time_savings_monthly_display',
  'cost_savings_monthly': 'cost_savings_monthly_display',
  'cost_savings_annual': 'cost_savings_annual_display',
  'payback_period': 'payback_period'
};

const replacements = {};
for (const [placeholder, field] of Object.entries(fieldMap)) {
  replacements[b(placeholder)] = r(field);
}
replacements[b('booking_link_15min')] = 'https://calendly.com/atomi-agency/15min';
replacements[b('booking_link_strategy')] = 'https://calendly.com/atomi-agency/strategy';

const requests = Object.entries(replacements).map(([placeholder, value]) => ({
  replaceAllText: {
    containsText: {
      text: placeholder,
      matchCase: true
    },
    replaceText: value
  }
}));

return [{
  json: {
    documentId,
    requests,
    report_url: 'https://docs.google.com/document/d/' + documentId + '/edit'
  }
}];

const d = $('Bundle: Audit Data').first().json;
const reportUrl = $('Build Replacements').first().json.report_url;
const inputBinary = $input.first().binary || {};

const emailHtml = `<p>Hi ${d.client_name},</p><p>Your AI Time Audit is complete. Please find your report attached.</p><p>Here is a quick summary:</p><ul><li>Process audited: ${d.process_name}</li><li>Current monthly cost: $${d.monthly_cost_display}</li><li>Estimated automation potential: ${d.automation_percentage}%</li><li>Projected monthly savings: $${d.cost_savings_monthly_display}</li></ul><p>The report includes three options for what to do next. If you would like to discuss the findings, the quickest way is to book a free 15-minute call:</p><p><a href="https://calendly.com/atomi-agency/15min">Book a Call</a></p><p>Questions? Just reply to this email.</p><p>Jeremy<br>Atomi Agency</p>`;

const validStatus = d.validation_passed ? 'PASSED' : 'ISSUES: ' + (d.validation_issues || []).join(', ');
const teamsMsg = 'New AI Time Audit report ready for review.\n\nClient: ' + d.client_name + '\nProcess: ' + d.process_name + '\nAutomation: ' + d.automation_percentage + '%\nMonthly savings: $' + d.cost_savings_monthly_display + '\n\nGoogle Doc: ' + reportUrl + '\n\nValidation: ' + validStatus + '\n\nAction required: Review draft email in Outlook, then send.';

return [{
  json: {
    email_html: emailHtml,
    email_subject: 'Your AI Time Audit Report is Ready - ' + d.client_name,
    email_to: d.customer_email,
    teams_message: teamsMsg,
    intake_record_id: $('Create Intake Record').first().json.id,
    automation_percentage: d.automation_percentage,
    cost_savings_monthly: d.cost_savings_monthly,
    report_url: reportUrl,
    validation_issues: d.validation_issues || []
  },
  binary: inputBinary
}];

// Build the complete audit context object.
// Combines: Typeform intake + Airtable Engagement + Airtable Company.

const intake = $('Parse Typeform').first().json;
const engagement = $('Get Engagement').first().json.fields;
const company = $('Get Company').first().json.fields;

// === Resolve client (business) name ===
const clientName = company.Name
  || [intake.first_name, intake.last_name].filter(Boolean).join(' ')
  || 'Client';

// === Engagement metadata ===
const engagementId = $('Get Engagement').first().json.id;
const engagementName = engagement['Engagement Name'] || '';
const engagementStatus = engagement.Status || 'Unknown';
const engagementType = engagement.Type || '';

// === Company metadata ===
const companyId = $('Get Company').first().json.id;
const companyIndustry = company.Industry || '';
const companySize = company.Size || '';
const companyWebsite = company.Website || '';

return [{
  json: {
    // === Identity ===
    customer_email: intake.customer_email,
    first_name: intake.first_name,
    last_name: intake.last_name,
    user_id: intake.user_id,
    client_name: clientName,

    // === Process intake ===
    process_name: intake.process_name,
    frustration_type: intake.frustration_type,
    monthly_volume: intake.monthly_volume,
    monthly_volume_raw: intake.monthly_volume_raw,
    time_per_instance: intake.time_per_instance,
    hourly_rate: intake.hourly_rate,
    error_rate: intake.error_rate,
    tools_involved: intake.tools_involved,           // string for AI prompts/report
tools_involved_array: intake.tools_involved_array, // array for Airtable multi-select
    decision_complexity: intake.decision_complexity,
    ideal_state: intake.ideal_state,
    freed_time_impact: intake.freed_time_impact,

    // === Sales qualification ===
    urgency: intake.urgency,
    urgency_raw: intake.urgency_raw,
    decision_maker: intake.decision_maker,
    decision_maker_raw: intake.decision_maker_raw,
    lead_quality: intake.lead_quality,

    // === CRM context ===
    engagement_id: engagementId,
    engagement_name: engagementName,
    engagement_status: engagementStatus,
    engagement_type: engagementType,
    company_id: companyId,
    company_industry: companyIndustry,
    company_size: companySize,
    company_website: companyWebsite,

    // === Metadata ===
    report_date: intake.report_date
  }
}];

// Calculate base metrics from intake data.
// Conservative approach: midpoints with tapered cap on extreme volumes.
// Display values use Australian formatting (commas, no currency symbol).

const ctx = $('Build Context').first().json;

// === Lookup tables ===
// Each range maps to [low, mid, high] so we have flexibility for future ranges.
const timeRanges = {
  '5-15min':   { low: 5,   mid: 10,   high: 15 },
  '15-30min':  { low: 15,  mid: 22.5, high: 30 },
  '30-60min':  { low: 30,  mid: 45,   high: 60 },
  '1-2hrs':    { low: 60,  mid: 90,   high: 120 },
  '2+hrs':     { low: 120, mid: 150,  high: 240 }
};

const rateRanges = {
  '$50-75/hr':   { low: 50,  mid: 62.50,  high: 75 },
  '$75-100/hr':  { low: 75,  mid: 87.50,  high: 100 },
  '$100-150/hr': { low: 100, mid: 125.00, high: 150 },
  '$150+/hr':    { low: 150, mid: 175.00, high: 250 }
};

const errorDecimals = {
  'Rarely (<2%)':     0.02,
  'Occasionally (~5%)': 0.05,
  'Often (10%+)':     0.12
};

// === Lookups with sensible fallbacks ===
const timeRange = timeRanges[ctx.time_per_instance] || timeRanges['15-30min'];
const rateRange = rateRanges[ctx.hourly_rate] || rateRanges['$75-100/hr'];
const errorDecimal = errorDecimals[ctx.error_rate] || 0.05;
const volume = parseInt(ctx.monthly_volume) || 0;

// === Realism cap ===
// Rationale: very high reported volumes tend to overstate true time —
// people batch, take shortcuts, or only spend full time on harder cases.
// Apply a gentle taper above 50 hours/month rather than a hard cliff.
const applyRealismTaper = (rawHours) => {
  if (rawHours <= 50) return rawHours;
  if (rawHours <= 100) return 50 + (rawHours - 50) * 0.9;
  return 50 + (50 * 0.9) + (rawHours - 100) * 0.75;
};

// === Core calculations using midpoints ===
const monthlyHoursRaw = (volume * timeRange.mid) / 60;
const monthlyHours = Math.round(applyRealismTaper(monthlyHoursRaw));
const monthlyCost = Math.round(monthlyHours * rateRange.mid);
const annualCost = monthlyCost * 12;
const annualHours = monthlyHours * 12;
const reworkCost = Math.round(monthlyCost * errorDecimal * 1.5);

// === Range bounds (for future use — confidence intervals, conservative quotes) ===
const monthlyHoursLow = Math.round(applyRealismTaper((volume * timeRange.low) / 60));
const monthlyHoursHigh = Math.round(applyRealismTaper((volume * timeRange.high) / 60));
const monthlyCostLow = Math.round(monthlyHoursLow * rateRange.low);
const monthlyCostHigh = Math.round(monthlyHoursHigh * rateRange.high);

// === Australian-formatted display strings ===
const fmt = (n) => n.toLocaleString('en-AU');

return [{
  json: {
    // === Inputs (handy for debugging) ===
    time_minutes_midpoint: timeRange.mid,
    hourly_rate_midpoint: rateRange.mid,
    error_rate_decimal: errorDecimal,
    volume_input: volume,

    // === Primary calculations (mid-point estimates) ===
    monthly_hours: monthlyHours,
    monthly_cost: monthlyCost,
    annual_hours: annualHours,
    annual_cost: annualCost,
    rework_cost: reworkCost,

    // === Range bounds (for future confidence intervals) ===
    monthly_hours_low: monthlyHoursLow,
    monthly_hours_high: monthlyHoursHigh,
    monthly_cost_low: monthlyCostLow,
    monthly_cost_high: monthlyCostHigh,

    // === Display formatted (en-AU) ===
    monthly_hours_display: fmt(monthlyHours),
    monthly_cost_display: fmt(monthlyCost),
    annual_hours_display: fmt(annualHours),
    annual_cost_display: fmt(annualCost),
    rework_cost_display: fmt(reworkCost),
    monthly_cost_range_display: `${fmt(monthlyCostLow)}–${fmt(monthlyCostHigh)}`
  }
}];

const ctx = $('Build Context').first().json;
const metrics = $('Calc: Current State').first().json;
const savings = $('Calc: Automation Potential').first().json;

const cleanQuote = (s) => (s || '').trim().replace(/"/g, '\\"');
const orNotProvided = (s) => s && String(s).trim() ? s : 'not specified';

const userMessage = `The following is intake data and calculated figures from a paid AI Time Audit client. Use this data to generate the requested section of their report.

<client_context>
Business name: ${ctx.client_name}
Industry: ${orNotProvided(ctx.company_industry)}
Company size: ${orNotProvided(ctx.company_size)}
</client_context>

<process_audit>
Process being audited: ${ctx.process_name}
Primary frustration: ${ctx.frustration_type}
Monthly volume: ${ctx.monthly_volume} times per month
Time per instance: ${ctx.time_per_instance}
Hourly rate of person doing work: ${ctx.hourly_rate}
Error/rework rate: ${ctx.error_rate}
Tools currently involved: ${ctx.tools_involved}
Decision complexity: ${ctx.decision_complexity}
</process_audit>

<client_voice>
What they said about their ideal state:
"${cleanQuote(ctx.ideal_state)}"

What they would do with freed time:
"${cleanQuote(ctx.freed_time_impact)}"
</client_voice>

<calculated_figures>
Current monthly hours: ${metrics.monthly_hours}
Current monthly cost: $${metrics.monthly_cost_display}
Current annual cost: $${metrics.annual_cost_display}
Rework cost per month: $${metrics.rework_cost_display}
Automation percentage: ${savings.automation_percentage}%
Monthly hours saved: ${savings.time_savings_monthly}
Monthly cost saved: $${savings.cost_savings_monthly_display}
Annual cost saved: $${savings.cost_savings_annual_display}
Payback period: ${savings.payback_period}
</calculated_figures>

<sales_signals>
Urgency level: ${ctx.urgency}
Decision-making authority: ${ctx.decision_maker}
</sales_signals>`;

return [{
  json: {
    ai_user_message: userMessage
  }
}];

// Calculate automation percentage AND apply to base metrics.
// Replaces the AI-based P1 + Validate Pct nodes with deterministic logic.
// The AI was just executing a lookup table — now we do it directly.

const ctx = $('Build Context').first().json;
const metrics = $('Calc: Current State').first().json;

// === Decision Complexity → base percentage range ===
// Use the midpoint of each documented range from the original P1 prompt.
const complexityBase = {
  'Simple rules / no judgment':                     80, // range 75-85, mid 80
  'Simple rules with occasional judgment calls':    68, // range 60-75, mid 67.5
  'Requires context or experience':                 53, // range 45-60, mid 52.5
  'Highly subjective / relationship-dependent':     38  // range 30-45, mid 37.5
};
let pct = complexityBase[ctx.decision_complexity] || 55; // safe fallback

// === Tool modifier ===
// Categorise mentioned tools to determine modifier.
const tools = (ctx.tools_involved || '').toLowerCase();
const apiConnectedTools = ['xero', 'quickbooks', 'myob', 'hubspot', 'salesforce', 
                            'pipedrive', 'monday', 'asana', 'slack', 'gmail', 
                            'outlook', 'google workspace', 'm365', 'microsoft 365',
                            'dynamics', 'zendesk', 'intercom', 'shopify', 'stripe'];
const manualIndicators = ['paper', 'phone', 'in-person', 'in person', 'physical mail',
                           'fax', 'handwritten'];
const spreadsheetOnly = ['spreadsheet', 'excel', 'google sheets'];

const hasApiTools = apiConnectedTools.some(t => tools.includes(t));
const hasManualTools = manualIndicators.some(t => tools.includes(t));
const hasOnlySpreadsheets = spreadsheetOnly.some(t => tools.includes(t)) && !hasApiTools;

if (hasManualTools) {
  pct -= 8; // -5 to -10, use -8
} else if (hasApiTools) {
  pct += 3; // 0 to +5, use +3
}
// Spreadsheet-only: no change (per prompt rules)

// === Volume modifier ===
// High volume + simple decisions = +3
// Low volume + complex decisions = -3
const volume = parseInt(ctx.monthly_volume) || 0;
const isSimpleDecision = ctx.decision_complexity === 'Simple rules / no judgment'
  || ctx.decision_complexity === 'Simple rules with occasional judgment calls';
const isComplexDecision = ctx.decision_complexity === 'Requires context or experience'
  || ctx.decision_complexity === 'Highly subjective / relationship-dependent';

if (volume >= 50 && isSimpleDecision) {
  pct += 3;
} else if (volume < 10 && isComplexDecision) {
  pct -= 3;
}

// === Apply hard bounds (30-85 per original spec) ===
if (pct < 30) pct = 30;
if (pct > 85) pct = 85;

// === Round to nearest 5 (round DOWN per "when in doubt, round down" rule) ===
pct = Math.floor(pct / 5) * 5;

// === Calculate savings using the percentage ===
const factor = pct / 100;
const timeSavingsMonthly  = Math.round(metrics.monthly_hours * factor);
const costSavingsMonthly  = Math.round(metrics.monthly_cost * factor);
const costSavingsAnnual   = costSavingsMonthly * 12;
const timeSavingsAnnual   = timeSavingsMonthly * 12;

// === Range bounds (uses Calculate Metrics range output) ===
const costSavingsMonthlyLow  = Math.round(metrics.monthly_cost_low * factor);
const costSavingsMonthlyHigh = Math.round(metrics.monthly_cost_high * factor);

// === Payback period ===
const implCost = 5000;
const paybackMonths = costSavingsMonthly > 0
  ? Math.ceil(implCost / costSavingsMonthly)
  : 0;
const paybackDisplay = paybackMonths <= 1
  ? '1 month'
  : paybackMonths <= 2
    ? '1-2 months'
    : `${paybackMonths - 1}-${paybackMonths} months`;

// === Australian-formatted display strings ===
const fmt = (n) => n.toLocaleString('en-AU');

return [{
  json: {
    automation_percentage: pct,
    time_savings_monthly: timeSavingsMonthly,
    time_savings_annual: timeSavingsAnnual,
    cost_savings_monthly: costSavingsMonthly,
    cost_savings_annual: costSavingsAnnual,
    payback_period: paybackDisplay,
    cost_savings_monthly_low: costSavingsMonthlyLow,
    cost_savings_monthly_high: costSavingsMonthlyHigh,
    time_savings_monthly_display: fmt(timeSavingsMonthly),
    time_savings_annual_display: fmt(timeSavingsAnnual),
    cost_savings_monthly_display: fmt(costSavingsMonthly),
    cost_savings_annual_display: fmt(costSavingsAnnual),
    cost_savings_range_display: `${fmt(costSavingsMonthlyLow)}–${fmt(costSavingsMonthlyHigh)}`,

    // Diagnostic info (handy for debugging, no harm leaving in)
    _decision_basis: {
      complexity: ctx.decision_complexity,
      complexity_base: complexityBase[ctx.decision_complexity],
      tools_modifier: hasManualTools ? -8 : (hasApiTools ? 3 : 0),
      volume_modifier: (volume >= 50 && isSimpleDecision) ? 3 : 
                        ((volume < 10 && isComplexDecision) ? -3 : 0),
      final: pct
    }
  }
}];

// Bundle all AI outputs with upstream data into one clean object.
// This is the bridge between the AI generation phase and the report assembly phase.
// Every downstream node (Build Replacements, Prepare Email, etc.) reads from here.

// === Helper: defensive AI text extraction ===
// LangChain Anthropic node returns content as an array of text objects.
// Order matters here — check the most-likely path first.
function extractAiText(nodeName) {
  try {
    const data = $(nodeName).first().json;

    // Most likely path: content array with text objects
    // (LangChain Anthropic node format)
    if (Array.isArray(data.content) && data.content[0]?.text) {
      return String(data.content[0].text).trim();
    }

    // Fallback: direct text field
    if (typeof data.text === 'string') {
      return data.text.trim();
    }

    // Fallback: content as string
    if (typeof data.content === 'string') {
      return data.content.trim();
    }

    // Fallback: nested message structure
    if (data.message?.content?.[0]?.text) {
      return String(data.message.content[0].text).trim();
    }

    if (typeof data.message?.content === 'string') {
      return data.message.content.trim();
    }

    return ''; // nothing found
  } catch (e) {
    return '';
  }
}

// === Helper: strip leading "- " from each line of a bullet list ===
// The Google Doc template provides its own bullet formatting, so the AI's
// markdown-style "- " prefix would produce double bullets.
function cleanBulletList(text) {
  return text
    .split('\n')
    .map(line => line.replace(/^\s*-\s*/, ''))
    .filter(line => line.trim())
    .join('\n');
}

// === Gather upstream data ===
const ctx = $('Build Context').first().json;
const metrics = $('Calc: Current State').first().json;
const savings = $('Calc: Automation Potential').first().json;

// === Extract AI outputs ===
// Narrative sections (3 new)
const execSummary           = extractAiText('AI: Exec Summary');
const currentState          = extractAiText('AI: Current State');
const automationPotential   = extractAiText('AI: Automation Potential');

// Analysis sections (5 existing)
const automatableStepsRaw   = extractAiText('AI: Automatable Steps');
const humanStepsRaw         = extractAiText('AI: Human Steps');
const solutionApproach      = extractAiText('AI: Solution Approach');
const integrationsRaw       = extractAiText('AI: Integrations + Trigger');
const exceptionHandling     = extractAiText('AI: Exception Handling');

// === Clean bullet lists (strip leading "- " so template bullets don't double up) ===
const automatableSteps = cleanBulletList(automatableStepsRaw);
const humanSteps       = cleanBulletList(humanStepsRaw);

// === Parse the two-line Integrations + Trigger output ===
let keyIntegrations = '';
let triggerEvent = '';
for (const line of integrationsRaw.split('\n')) {
  const trimmed = line.trim();
  if (trimmed.startsWith('KEY_INTEGRATIONS:')) {
    keyIntegrations = trimmed.replace('KEY_INTEGRATIONS:', '').trim();
  }
  if (trimmed.startsWith('TRIGGER_EVENT:')) {
    triggerEvent = trimmed.replace('TRIGGER_EVENT:', '').trim();
  }
}

// === Derive a short "remaining human work" phrase for the exec summary ===
// KNOWN LIMITATION: Currently uses the first human step bullet, lowercased.
// Can produce awkward grammar in the exec summary sentence. Worth revisiting.
// Note: we derive this from the RAW list (before bullet stripping) because
// the raw format is predictable for parsing.
const humanStepLines = humanStepsRaw.split('\n').filter(l => l.trim().startsWith('-'));
const remainingHumanWork = humanStepLines.length > 0
  ? humanStepLines[0].replace(/^-\s*/, '').toLowerCase().trim()
  : 'tasks requiring judgement';

// === Validation ===
// Non-blocking: we flag issues but pass content through. Teams notification
// will surface failures so you can manually review the draft report.
// Validation is done against RAW outputs to catch AI drift before cleaning.
const validationIssues = [];

// Automatable steps: 3-6 bullets
const autoStepCount = automatableStepsRaw.split('\n').filter(l => l.trim().startsWith('-')).length;
if (autoStepCount < 3 || autoStepCount > 6) {
  validationIssues.push(`Automatable Steps has ${autoStepCount} bullets (expected 3-6)`);
}

// Human steps: 2-4 bullets
if (humanStepLines.length < 2 || humanStepLines.length > 4) {
  validationIssues.push(`Human Steps has ${humanStepLines.length} bullets (expected 2-4)`);
}

// Solution approach starts correctly
if (!solutionApproach.startsWith('The automation would')) {
  validationIssues.push('Solution Approach does not start with "The automation would"');
}

// Solution approach word count
const solutionWords = solutionApproach.split(/\s+/).filter(w => w.length > 0).length;
if (solutionWords < 35 || solutionWords > 65) {
  validationIssues.push(`Solution Approach is ${solutionWords} words (expected 40-60, allow 35-65)`);
}

// Integrations + Trigger parsed
if (!keyIntegrations) {
  validationIssues.push('KEY_INTEGRATIONS could not be parsed from AI output');
}
if (!triggerEvent) {
  validationIssues.push('TRIGGER_EVENT could not be parsed from AI output');
}

// Exception handling word count and start
const exceptionWords = exceptionHandling.split(/\s+/).filter(w => w.length > 0).length;
if (exceptionWords < 8 || exceptionWords > 20) {
  validationIssues.push(`Exception Handling is ${exceptionWords} words (expected 8-20)`);
}
if (/^(when|if)/i.test(exceptionHandling)) {
  validationIssues.push('Exception Handling starts with "when" or "if" (should start with a noun)');
}

// Exec Summary word count (60-80, allow 50-90)
const execWords = execSummary.split(/\s+/).filter(w => w.length > 0).length;
if (execWords < 50 || execWords > 90) {
  validationIssues.push(`Exec Summary is ${execWords} words (expected 60-80)`);
}

// Current State word count (90-130, allow 80-150)
const currentStateWords = currentState.split(/\s+/).filter(w => w.length > 0).length;
if (currentStateWords < 80 || currentStateWords > 150) {
  validationIssues.push(`Current State is ${currentStateWords} words (expected 90-130)`);
}

// Automation Potential word count (50-70, allow 40-90)
const autoPotentialWords = automationPotential.split(/\s+/).filter(w => w.length > 0).length;
if (autoPotentialWords < 40 || autoPotentialWords > 90) {
  validationIssues.push(`Automation Potential is ${autoPotentialWords} words (expected 50-70)`);
}

// === Catch silent extraction failures ===
const extractionFailures = [];
if (!execSummary) extractionFailures.push('Exec Summary');
if (!currentState) extractionFailures.push('Current State');
if (!automationPotential) extractionFailures.push('Automation Potential');
if (!automatableStepsRaw) extractionFailures.push('Automatable Steps');
if (!humanStepsRaw) extractionFailures.push('Human Steps');
if (!solutionApproach) extractionFailures.push('Solution Approach');
if (!integrationsRaw) extractionFailures.push('Integrations + Trigger');
if (!exceptionHandling) extractionFailures.push('Exception Handling');
if (extractionFailures.length > 0) {
  validationIssues.unshift(`AI EXTRACTION FAILED for: ${extractionFailures.join(', ')}`);
}

// === Build the output bundle ===
return [{
  json: {
    // === Upstream data passthrough ===
    ...ctx,
    ...metrics,
    ...savings,

    // === AI narrative sections ===
    exec_summary: execSummary,
    current_state: currentState,
    automation_potential_intro: automationPotential,

    // === AI analysis sections (bullets cleaned for template insertion) ===
    automatable_steps: automatableSteps,
    human_required_steps: humanSteps,
    solution_approach: solutionApproach,
    key_integrations: keyIntegrations,
    trigger_event: triggerEvent,
    exception_handling: exceptionHandling,
    remaining_human_work: remainingHumanWork,

    // === Quality status ===
    validation_passed: validationIssues.length === 0,
    validation_issues: validationIssues,
    validation_summary: validationIssues.length === 0 
      ? 'PASSED' 
      : `${validationIssues.length} issue(s): ${validationIssues.slice(0, 2).join('; ')}${validationIssues.length > 2 ? '...' : ''}`
  }
}];
